	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

func TestCompactDiffFormatter(t *testing.T) {
	tests := map[string]struct {
		plan *plans.Plan
		want string
	}{
		"empty plan": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{},
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
					},
				},
			},
			want: "\n  [green]+[reset] Create:\n  aws_instance.example\n\nPlan: 1 to add.\n",
		},
		"single update": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
						},
					},
				},
			},
			want: "\n  [yellow]~[reset] Update:\n  aws_instance.example\n\nPlan: 1 to change.\n",
		},
		"single delete": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			want: "\n  [red]-[reset] Delete:\n  aws_instance.example\n\nPlan: 1 to destroy.\n",
		},
		"mixed changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "web",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "db",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "old",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			want: "\n  [green]+[reset] Create:\n  aws_instance.web\n\n  [yellow]~[reset] Update:\n  aws_instance.db\n\n  [red]-[reset] Delete:\n  aws_security_group.old\n\nPlan: 1 to add, 1 to change, 1 to destroy.\n",
		},
		"no-op changes are skipped": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.NoOp,
							},
						},
					},
				},
			},
			want: "",
		},
		"multiple resources with same action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "web1",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "web2",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
					},
				},
			},
			want: "\n  [green]+[reset] Create:\n  aws_instance.web1\n  aws_instance.web2\n\nPlan: 2 to add.\n",
		},
		"deposed resources are skipped": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.DeposedKey("old"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
					},
				},
			},
			want: "",
		},
		"replace actions": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.DeleteThenCreate,
							},
						},
					},
				},
			},
			want: "\n[red]-[reset]/[green]+[reset] Replace (delete then create):\n  aws_instance.example\n\nPlan: 1 to replace.\n",
		},
		"nil plan": {
			plan: nil,
			want: "",
		},
		"nil changes": {
			plan: &plans.Plan{
				Changes: nil,
			},
			want: "",
		},
	}

	formatter := &CompactDiffFormatter{}
	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(tc.plan, nil)
			if diff := cmp.Diff(tc.want, got); diff != "" {
				t.Errorf("unexpected output:\n%s", diff)
			}
		})
	}
}

func TestCompactDiffFormatterSorted(t *testing.T) {
	// Test that resources are sorted alphabetically within each action group
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "zebra",
							},
							Key: nil,
						},
					},
					DeposedKey: states.NotDeposed,
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "alpha",
							},
							Key: nil,
						},
					},
					DeposedKey: states.NotDeposed,
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, nil)

	// The output should have alpha before zebra
	alphaIdx := len("  [green]+[reset] Create:\n  ")
	zebra := "zebra"
	alpha := "alpha"

	if idx := len(got); idx < len(zebra) {
		t.Fatalf("output too short")
	}

	// Find positions of resource names in output
	alphaPos := -1
	zebraPos := -1

	for i := 0; i < len(got)-len(alpha); i++ {
		if got[i:i+len(alpha)] == alpha && i > 20 { // After the header
			alphaPos = i
			break
		}
	}

	for i := 0; i < len(got)-len(zebra); i++ {
		if got[i:i+len(zebra)] == zebra && i > 20 { // After the header
			zebraPos = i
			break
		}
	}

	if alphaPos == -1 || zebraPos == -1 {
		t.Fatalf("could not find resource names in output: %s", got)
	}

	if alphaPos >= zebraPos {
		t.Errorf("resources not sorted: alpha at %d, zebra at %d", alphaPos, zebraPos)
	}
}

func TestFormatActionName(t *testing.T) {
	tests := map[plans.Action]string{
		plans.Create:           "Create",
		plans.Update:           "Update",
		plans.Delete:           "Delete",
		plans.DeleteThenCreate: "Replace (delete then create)",
		plans.CreateThenDelete: "Replace (create then delete)",
		plans.Read:             "Read",
		plans.Forget:           "Forget",
		plans.CreateThenForget: "Forget",
		plans.Renew:            "Renew",
		plans.Open:             "Open",
		plans.Close:            "Close",
	}

	for action, expected := range tests {
		t.Run(string(action), func(t *testing.T) {
			got := formatActionName(action)
			if got != expected {
				t.Errorf("got %q, want %q", got, expected)
			}
		})
	}
}

func TestFormatSummary(t *testing.T) {
	tests := map[string]struct {
		counts map[plans.Action]int
		want   string
	}{
		"single action": {
			counts: map[plans.Action]int{plans.Create: 1},
			want:   "Plan: 1 to add.\n",
		},
		"multiple actions": {
			counts: map[plans.Action]int{
				plans.Create: 2,
				plans.Update: 1,
				plans.Delete: 3,
			},
			want: "Plan: 2 to add, 1 to change, 3 to destroy.\n",
		},
		"replace actions": {
			counts: map[plans.Action]int{
				plans.DeleteThenCreate: 1,
				plans.Create:           1,
			},
			want: "Plan: 1 to add, 1 to replace.\n",
		},
		"empty counts": {
			counts: map[plans.Action]int{},
			want:   "No changes.\n",
		},
		"zero counts": {
			counts: map[plans.Action]int{
				plans.Create: 0,
				plans.Update: 0,
			},
			want: "No changes.\n",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatSummary(tc.counts)
			if got != tc.want {
				t.Errorf("got %q, want %q", got, tc.want)
			}
		})
	}
}

