								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			want: "\n  [red]-[reset] Delete:\n  aws_instance.example\n\nPlan: 1 to destroy.\n",
		},
		"mixed changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "web",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "db",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "old",
									},
									Key: nil,
								},
							},
							DeposedKey: states.NotDeposed,
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			want: "\n  [green]+[reset] Create:\n  aws_instance.web\n\n  [yellow]~[reset] Update:\n  aws_instance.db\n\n  [red]-[reset] Delete:\n  aws_security_group.old\n\nPlan: 1 to add, 1 to change, 1 to destroy.\n",
		},
		"no-op changes are skipped": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
